import React, { useState, useEffect } from 'react';
import './Results.css';

export default function Results() {
  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const ctrl = new AbortController();
    // Fetch products with the fields we need: image (thumbnail), name (title), and description
    fetch('https://dummyjson.com/products?limit=8&select=id,title,thumbnail,description', { signal: ctrl.signal })
      .then(r => { if (!r.ok) throw new Error('Failed to fetch products'); return r.json(); })
      .then(d => { 
        setItems(d.products); 
        setLoading(false); 
      })
      .catch(e => { 
        if (e.name !== 'AbortError') { 
          setError('Could not load product data.'); 
          setLoading(false); 
        } 
      });
    return () => ctrl.abort();
  }, []);

  return (
    <section className="results-section">
      <div className="results-inner">
        <h2 className="results-title">Popular Products</h2>

        {loading && (
          <div className="results-grid">
            {[...Array(8)].map((_, i) => (
              <div key={i} className="skeleton-card">
                <div className="skel-img" />
                <div className="skel-line short" />
                <div className="skel-line long" />
              </div>
            ))}
          </div>
        )}

        {error && (
          <div className="results-error">
            <p>⚠️ {error}</p>
            <button onClick={() => window.location.reload()}>Retry</button>
          </div>
        )}

        {!loading && !error && (
          <div className="results-grid">
            {items.map((item) => (
              <div key={item.id} className="result-card">
                <div className="rc-img-wrap">
                  <img
                    src={item.thumbnail}
                    alt={item.title}
                    className="rc-img"
                  />
                </div>
                <div className="rc-body">
                  <span className="rc-type">{item.title}</span>
                  <span className="rc-dur" title={item.description}>
                    {item.description.length > 100 
                      ? `${item.description.substring(0, 100)}...` 
                      : item.description}
                  </span>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </section>
  );
}
